	 (1,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,NULL,'Айо уе?','2026-05-06 21:05:34'),
	 (1,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,NULL,'ахахах да Симба','2026-05-06 21:05:37'),
	 (1,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,1,'ну ляпнул','2026-05-06 21:05:43'),
	 (1,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,NULL,'мда ничего нового как бы ожидаемо','2026-05-06 21:09:11'),
	 (1,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,NULL,'да ты что а еще что расскажешь?','2026-05-06 21:09:19'),
	 (1,'f0000002-0000-4000-8000-000000000002'::uuid,NULL,'Бобры сильнее финала, чем начало.','2026-05-07 12:00:00'),
	 (1,'f0000003-0000-4000-8000-000000000003'::uuid,NULL,'Иронию не въехала, но пара сцен смешные.','2026-05-07 12:01:00'),
	 (1,'f0000004-0000-4000-8000-000000000004'::uuid,6,'Согласен, середина тянет резину.','2026-05-07 12:02:00'),
	 (2,'f0000001-0000-4000-8000-000000000001'::uuid,NULL,'Вестерн на тестовых декорациях — зашло.','2026-05-07 12:03:00'),
	 (2,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,NULL,'Очень спокойный темп, люблю.','2026-05-07 12:04:00'),
	 (2,'f0000002-0000-4000-8000-000000000002'::uuid,9,'Операторская работа здесь топ.','2026-05-07 12:05:00'),
	 (2,'f0000003-0000-4000-8000-000000000003'::uuid,NULL,'Финал честный, без лишнего сахара.','2026-05-07 12:06:00'),
	 (3,'f0000001-0000-4000-8000-000000000001'::uuid,NULL,'Шесть из десяти, не мой юмор.','2026-05-07 12:07:00'),
	 (3,'f0000004-0000-4000-8000-000000000004'::uuid,NULL,'Зато коротко и совсем без воды.','2026-05-07 12:08:00'),
	 (3,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,13,'Я больше за абсурд в таких штуках.','2026-05-07 12:09:00'),
	 (4,'f0000002-0000-4000-8000-000000000002'::uuid,NULL,'Серые будни как док про офис, кайф.','2026-05-07 12:10:00'),
	 (4,'f0000003-0000-4000-8000-000000000003'::uuid,NULL,'Тёплый фильм, хочется чаю с лимоном.','2026-05-07 12:11:00'),
	 (4,'f0000001-0000-4000-8000-000000000001'::uuid,16,'Да, палитра идеальная для темы.','2026-05-07 12:12:00'),
	 (5,'f0000002-0000-4000-8000-000000000002'::uuid,NULL,'Точно пересмотр через год сделаю.','2026-05-07 12:13:00'),
	 (5,'f0000004-0000-4000-8000-000000000004'::uuid,NULL,'Саундтрек уже в плейлисте лежит.','2026-05-07 12:14:00'),
	 (5,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,NULL,'Сцена на станции просто огонь.','2026-05-07 12:15:00'),
	 (6,'f0000002-0000-4000-8000-000000000002'::uuid,NULL,'Лифт без кнопок — метафора жизни.','2026-05-07 12:16:00'),
