	 (7,'f0000003-0000-4000-8000-000000000003'::uuid,NULL,'Звёздный дождь визуально просто шик.','2026-05-07 12:19:00'),
	 (7,'f0000001-0000-4000-8000-000000000001'::uuid,NULL,'Чуть затянуто во втором акте, увы.','2026-05-07 12:20:00'),
	 (7,'f0000004-0000-4000-8000-000000000004'::uuid,NULL,'Но картинка почти всё спасает.','2026-05-07 12:21:00'),
	 (7,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,25,'Про визуал с тобой полностью согласна.','2026-05-07 12:22:00'),
	 (8,'f0000004-0000-4000-8000-000000000004'::uuid,NULL,'Тихая гавань — мягкий и честный финал.','2026-05-07 12:23:00'),
	 (8,'f0000002-0000-4000-8000-000000000002'::uuid,NULL,'Семейка трогает без лишней мелодрамы.','2026-05-07 12:24:00'),
