	 (9,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,NULL,'С друзьями зашло лучше второго раза.','2026-05-07 12:26:00'),
	 (9,'f0000001-0000-4000-8000-000000000001'::uuid,NULL,'Абсурд в меру, не переборщили.','2026-05-07 12:27:00'),
	 (9,'f0000003-0000-4000-8000-000000000003'::uuid,NULL,'Титры не досмотрели — жалко концовку.','2026-05-07 12:28:00'),
	 (9,'f0000004-0000-4000-8000-000000000004'::uuid,32,'Второй раз реально лучше первого.','2026-05-07 12:29:00'),
	 (10,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,NULL,'Космос и дождь — полностью мой вайб.','2026-05-07 12:30:00'),
	 (10,'f0000002-0000-4000-8000-000000000002'::uuid,NULL,'Чуть предсказуем twist, но в целом ок.','2026-05-07 12:31:00'),
	 (10,'f0000001-0000-4000-8000-000000000001'::uuid,NULL,'Хочется обсуждать спойлеры отдельным чатом.','2026-05-07 12:32:00'),
	 (10,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,36,'Вайб понятен, саунд тоже зашёл сюда.','2026-05-07 12:33:00'),
	 (10,'f0000003-0000-4000-8000-000000000003'::uuid,NULL,'Ещё один прогон и в список любимых.','2026-05-07 12:34:00'),
	 (3,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,NULL,'Первая сцена цепляет, дальше слабее.','2026-05-07 12:35:00'),
