	 (7,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,NULL,'Один кадр с дождём — вот ради чего шёл.','2026-05-07 12:38:00'),
	 (8,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,29,'Финал оставил тихое тепло внутри.','2026-05-07 12:39:00'),
	 (2,'f0000004-0000-4000-8000-000000000004'::uuid,10,'Спокойный темп иногда засыпаешь, но ок.','2026-05-07 12:40:00'),
	 (4,'5f1370d8-8150-49b5-bafe-2d757636d64b'::uuid,17,'Чай с лимоном — идеальное сопровождение.','2026-05-07 12:41:00'),
	 (1,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,7,'Смешно, но не настолько чтобы в кино идти.','2026-05-07 12:42:00'),
	 (9,'84d5d773-465f-4194-bd78-d94b9f3de41d'::uuid,NULL,'В зале смеялись громче, чем дома.','2026-05-07 12:43:00'),
	 (10,'f0000004-0000-4000-8000-000000000004'::uuid,38,'Чат со спойлерами уже создала, жду вас.','2026-05-07 12:44:00');
